function depositWithExpiry(
    address payable vault,
    address asset,
    uint amount,
    string memory memo,
    uint expiration
  ) external payable {
    require(block.timestamp < expiration, "THORChain_Router: expired");
    _deposit(vault, asset, amount, memo);
  }

function _deposit(
    address payable vault,
    address asset,
    uint amount,
    string memory memo
  ) private nonReentrant {
    uint safeAmount;
    if (asset == address(0)) {
      safeAmount = msg.value;
      bool success = vault.send(safeAmount);
      require(success);
    } else {
      require(msg.value == 0, "unexpected eth");
      safeAmount = safeTransferFrom(asset, amount);
      _vaultAllowance[vault][asset] += safeAmount;
    }
    emit Deposit(vault, asset, safeAmount, memo);
  }

function deposit(
    address payable vault,
    address asset,
    uint256 amount,
    string memory memo
  ) public payable nonReentrant {
    uint256 safeAmount;
    if (asset == address(0)) {
      safeAmount = msg.value;
      bool success = vault.send(safeAmount);
      require(success, "Send Failed");
    } else {
      require(msg.value == 0, "unexpected avax");
      safeAmount = safeTransferFrom(asset, amount);
      _vaultAllowance[vault][asset] += safeAmount;
    }
    emit Deposit(vault, asset, safeAmount, memo);
  }
